{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyOIggv+WHYW0MjvH8VK0kBY"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":1,"metadata":{"id":"A9NjujeTyk5t","executionInfo":{"status":"ok","timestamp":1772391986937,"user_tz":-180,"elapsed":7709,"user":{"displayName":"Sema Hacıbekiroğlu","userId":"10657115845303637897"}}},"outputs":[],"source":["from sklearn.svm import SVC\n","from sklearn.metrics import accuracy_score, precision_score, recall_score, f1_score\n","\n","class SVMModel:\n","    def __init__(self):\n","        self.model = SVC(kernel=\"rbf\", C=1, gamma=\"scale\")\n","\n","    def train(self, X_train, y_train):\n","        self.model.fit(X_train, y_train)\n","\n","    def evaluate(self, X_test, y_test):\n","        y_pred = self.model.predict(X_test)\n","        return {\n","            \"Accuracy\": accuracy_score(y_test, y_pred),\n","            \"Precision\": precision_score(y_test, y_pred),\n","            \"Recall\": recall_score(y_test, y_pred),\n","            \"F1 Score\": f1_score(y_test, y_pred)\n","        }"]}]}